import{_ as n,o as h,c as a,ag as i}from"./chunks/framework.CxZWPeXl.js";const b=JSON.parse('{"title":"Hướng dẫn nhanh","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started.md","filePath":"getting-started.md"}'),o={name:"getting-started.md"};function c(r,t,e,d,u,g){return h(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="huong-dan-nhanh" tabindex="-1">Hướng dẫn nhanh <a class="header-anchor" href="#huong-dan-nhanh" aria-label="Permalink to &quot;Hướng dẫn nhanh&quot;">​</a></h1><blockquote><p>Từ đăng nhập đến khi hoàn thành bài thực hành đầu tiên chỉ mất 5 phút.</p></blockquote><h2 id="yeu-cau-he-thong" tabindex="-1">Yêu cầu Hệ thống <a class="header-anchor" href="#yeu-cau-he-thong" aria-label="Permalink to &quot;Yêu cầu Hệ thống&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tiêu chí</th><th>Yêu cầu</th></tr></thead><tbody><tr><td>Trình duyệt</td><td>Phiên bản mới nhất của Chrome, Edge, Firefox, Safari</td></tr><tr><td>Mạng</td><td>Kết nối internet ổn định</td></tr><tr><td>Thiết bị</td><td>Máy tính bàn, Laptop, Máy tính bảng (Hỗ trợ thiết kế đa màn hình)</td></tr><tr><td>Micro</td><td>Tùy chọn, cần thiết nếu dùng tính năng nhập bằng giọng nói</td></tr></tbody></table><h2 id="đang-nhap" tabindex="-1">Đăng nhập <a class="header-anchor" href="#đang-nhap" aria-label="Permalink to &quot;Đăng nhập&quot;">​</a></h2><p>AI Coach sử dụng hệ thống đăng nhập SSO cấp doanh nghiệp. Bạn không cần đăng ký tài khoản riêng.</p><h3 id="phuong-thuc-đang-nhap" tabindex="-1">Phương thức đăng nhập <a class="header-anchor" href="#phuong-thuc-đang-nhap" aria-label="Permalink to &quot;Phương thức đăng nhập&quot;">​</a></h3><ol><li><strong>Đăng nhập bằng Microsoft</strong> — Sử dụng tài khoản Microsoft của công ty.</li><li><strong>Đăng nhập bằng Google</strong> — Sử dụng tài khoản Google của công ty.</li></ol><blockquote><p>Các tùy chọn đăng nhập phụ thuộc vào cài đặt của công ty bạn. Đôi khi chỉ có tùy chọn Microsoft.</p></blockquote><h3 id="khac-phuc-su-co-đang-nhap" tabindex="-1">Khắc phục sự cố đăng nhập <a class="header-anchor" href="#khac-phuc-su-co-đang-nhap" aria-label="Permalink to &quot;Khắc phục sự cố đăng nhập&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tình huống</th><th>Mô tả</th><th>Giải pháp</th></tr></thead><tbody><tr><td>Tài khoản chưa đăng ký</td><td>Tài khoản chưa được thêm vào hệ thống</td><td>Liên hệ quản trị viên</td></tr><tr><td>Tài khoản bị khóa</td><td>Cảnh báo &quot;Tài khoản bị vô hiệu hóa&quot;</td><td>Liên hệ quản trị viên để kiểm tra trạng thái</td></tr><tr><td>Xác thực thất bại</td><td>Cảnh báo &quot;Đăng nhập thất bại&quot;</td><td>Tải lại trang hoặc xóa bộ nhớ cache</td></tr></tbody></table><h2 id="tong-quan-giao-dien" tabindex="-1">Tổng quan Giao diện <a class="header-anchor" href="#tong-quan-giao-dien" aria-label="Permalink to &quot;Tổng quan Giao diện&quot;">​</a></h2><h3 id="thanh-đieu-huong-menu-tren-cung" tabindex="-1">Thanh điều hướng (Menu trên cùng) <a class="header-anchor" href="#thanh-đieu-huong-menu-tren-cung" aria-label="Permalink to &quot;Thanh điều hướng (Menu trên cùng)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Thành phần</th><th>Mô tả</th></tr></thead><tbody><tr><td>Logo AI Coach</td><td>Nhấp để quay lại Bảng điều khiển</td></tr><tr><td>Bộ chuyển đổi ngôn ngữ</td><td>Thay đổi ngôn ngữ giao diện (Tiếng Việt / Phồn thể)</td></tr><tr><td>Trợ lý Kiến thức</td><td>Mở hộp thoại Hỏi &amp; Đáp (cần quyền truy cập)</td></tr><tr><td>Cài đặt</td><td>Dành cho quản trị viên cấu hình hệ thống</td></tr><tr><td>Đăng xuất</td><td>Đăng xuất khỏi hệ thống an toàn</td></tr></tbody></table><h3 id="cac-trang-chinh" tabindex="-1">Các Trang Chính <a class="header-anchor" href="#cac-trang-chinh" aria-label="Permalink to &quot;Các Trang Chính&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Trang</th><th>Đường dẫn</th><th>Mô tả</th></tr></thead><tbody><tr><td>Bảng điều khiển</td><td><code>/dashboard</code></td><td>Trang chủ, hiển thị thống kê học tập và dữ liệu gần đây</td></tr><tr><td>Thực hành</td><td><code>/chat</code></td><td>Trò chuyện mô phỏng với khách hàng AI</td></tr><tr><td>Báo cáo đánh giá</td><td><code>/review/:sessionId</code></td><td>Xem kết quả phân tích đánh giá sau thực hành</td></tr><tr><td>Lịch sử</td><td><code>/practice-history</code></td><td>Xem danh sách tất cả các bài thực hành trước</td></tr></tbody></table><h2 id="bai-thuc-hanh-đau-tien-quy-trinh-hoan-chinh" tabindex="-1">Bài Thực Hành Đầu Tiên: Quy trình hoàn chỉnh <a class="header-anchor" href="#bai-thuc-hanh-đau-tien-quy-trinh-hoan-chinh" aria-label="Permalink to &quot;Bài Thực Hành Đầu Tiên: Quy trình hoàn chỉnh&quot;">​</a></h2><h3 id="buoc-1-xem-bang-đieu-khien" tabindex="-1">Bước 1: Xem Bảng điều khiển <a class="header-anchor" href="#buoc-1-xem-bang-đieu-khien" aria-label="Permalink to &quot;Bước 1: Xem Bảng điều khiển&quot;">​</a></h3><p>Đăng nhập để xem bảng điều khiển. Các chỉ số sẽ là 0 trong lần đầu tiên sử dụng.</p><h3 id="buoc-2-bat-đau-thuc-hanh" tabindex="-1">Bước 2: Bắt đầu Thực hành <a class="header-anchor" href="#buoc-2-bat-đau-thuc-hanh" aria-label="Permalink to &quot;Bước 2: Bắt đầu Thực hành&quot;">​</a></h3><p>Nhấp vào nút <strong>&quot;Bắt đầu trò chuyện&quot;</strong> (Start Conversation) trên Bảng điều khiển.</p><h3 id="buoc-3-chon-kich-ban" tabindex="-1">Bước 3: Chọn Kịch bản <a class="header-anchor" href="#buoc-3-chon-kich-ban" aria-label="Permalink to &quot;Bước 3: Chọn Kịch bản&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Kịch bản</th><th>Mô tả</th></tr></thead><tbody><tr><td>Chân dung Ngẫu nhiên</td><td>Hệ thống tạo ngẫu nhiên một khách hàng để luyện tập. Phù hợp để bắt đầu nhanh.</td></tr><tr><td>Chân dung Tùy chỉnh</td><td>Bạn tự định nghĩa đặc điểm khách hàng để huấn luyện cho tình huống cụ thể.</td></tr></tbody></table><blockquote><p><strong>Mẹo:</strong> Khuyến nghị chọn <strong>&quot;Chân dung Ngẫu nhiên&quot;</strong> cho lần đầu tiên.</p></blockquote><h3 id="buoc-4-tro-chuyen" tabindex="-1">Bước 4: Trò chuyện <a class="header-anchor" href="#buoc-4-tro-chuyen" aria-label="Permalink to &quot;Bước 4: Trò chuyện&quot;">​</a></h3><p>Giao diện trò chuyện bao gồm:</p><ul><li><strong>Bên trái</strong>: Thông tin hồ sơ khách hàng</li><li><strong>Ở giữa</strong>: Cửa sổ trò chuyện với khách hàng AI</li><li><strong>Bên trên</strong>: Đồng hồ bấm giờ để theo dõi thời lượng Nhập tin nhắn của bạn và nhấn Enter để gửi.</li></ul><h3 id="buoc-5-ket-thuc" tabindex="-1">Bước 5: Kết thúc <a class="header-anchor" href="#buoc-5-ket-thuc" aria-label="Permalink to &quot;Bước 5: Kết thúc&quot;">​</a></h3><p>Khi hoàn tất, hãy nhấp vào nút <strong>&quot;Kết thúc trò chuyện&quot;</strong> (End Conversation) ở góc trên bên phải. Hệ thống sẽ tự động tổng hợp và lưu kết quả.</p><h3 id="buoc-6-xem-đanh-gia" tabindex="-1">Bước 6: Xem Đánh giá <a class="header-anchor" href="#buoc-6-xem-đanh-gia" aria-label="Permalink to &quot;Bước 6: Xem Đánh giá&quot;">​</a></h3><p>Báo cáo sẽ mất từ 30 giây đến 2 phút để tạo và phân tích tự động. Nó bao gồm:</p><ul><li><strong>Đánh giá Toàn diện</strong>: Đánh giá hiệu suất chung và theo giai đoạn</li><li><strong>Phản hồi Từng câu</strong>: Các nhận xét chi tiết cho từng tin nhắn bạn đã gửi</li></ul><hr><h2 id="buoc-tiep-theo" tabindex="-1">Bước tiếp theo <a class="header-anchor" href="#buoc-tiep-theo" aria-label="Permalink to &quot;Bước tiếp theo&quot;">​</a></h2><ul><li>Tìm hiểu toàn bộ chức năng của <a href="./dashboard.html">Bảng điều khiển</a></li><li>Khám phá cài đặt nâng cao của chức năng <a href="./practice.html">Thực hành</a></li><li>Hiểu các chỉ số trong <a href="./evaluation.html">Báo cáo Đánh giá</a></li></ul>',35)])])}const s=n(o,[["render",c]]);export{b as __pageData,s as default};
